<!-- PROTOTYPE fixture data — local-only; deliberately not connected to APIs. -->
<template>
  <section class="mock-visual">
    <template v-if="scope === 'conversation' && surfaceId === 'talk'">
      <div class="chat-preview"><header><i class="avatar elen">伊</i><span><b>伊澜</b><small>旧城图书馆 · 正在输入故事</small></span><em>● 感知开启</em></header><div class="thread"><article v-for="message in messages" :key="message.id" :class="message.role"><i v-if="message.role === 'assistant'" class="avatar elen">伊</i><div><small>{{ message.role === 'assistant' ? '伊澜 · 22:14' : '你 · 22:15' }}</small><p>{{ message.text }}</p></div></article></div><form @submit.prevent="send"><input v-model="draft" placeholder="写一条虚拟消息…"/><button>发送 ↗</button></form></div>
    </template>
    <template v-else-if="scope === 'conversation' && surfaceId === 'start' || scope === 'studio' && surfaceId === 'persona'">
      <div class="persona-grid"><button v-for="persona in personas" :key="persona.name" :class="{ selected: selectedPersona === persona.name }" @click="selectedPersona = persona.name"><i :class="['portrait', persona.tone]">{{ persona.initial }}</i><b>{{ persona.name }}</b><small>{{ persona.note }}</small><span>{{ persona.tags }}</span></button></div>
    </template>
    <template v-else-if="scope === 'studio'">
      <div class="asset-list"><article v-for="asset in assetRecords" :key="asset.title"><i>{{ asset.icon }}</i><span><b>{{ asset.title }}</b><small>{{ asset.meta }}</small></span><em>{{ asset.value }}</em></article></div>
    </template>
    <template v-else-if="scope === 'insights' && surfaceId === 'mood'">
      <div class="mood-grid"><article v-for="day in moodDays" :key="day.date"><b>{{ day.date }}</b><span>{{ day.emoji }}</span><small>{{ day.label }}</small></article></div>
    </template>
    <template v-else-if="scope === 'insights'">
      <div class="timeline"><article v-for="item in insightItems" :key="item.title"><i></i><span><b>{{ item.title }}</b><small>{{ item.meta }}</small></span><em>{{ item.value }}</em></article></div>
    </template>
    <template v-else>
      <div class="account"><header><i>林</i><span><b>林川</b><small>linc@emiya.local</small></span><em>创作已同步</em></header><article v-for="device in devices" :key="device.name"><i>{{ device.icon }}</i><span><b>{{ device.name }}</b><small>{{ device.meta }}</small></span><em>{{ device.state }}</em></article></div>
    </template>
  </section>
</template>

<script setup lang="ts">
import { computed, ref } from 'vue'
const props = defineProps<{ scope: 'conversation' | 'studio' | 'insights' | 'account'; surfaceId: string }>()
const personas = [{ name: '伊澜', initial: '伊', tone: 'elen', note: '旧城的夜班图书管理员', tags: '治愈 · 旧城' }, { name: '诺娅', initial: '诺', tone: 'noa', note: '在港口等一封迟到的信', tags: '悬疑 · 海港' }, { name: '阿斯特', initial: '阿', tone: 'aster', note: '把王都礼仪背得一字不差', tags: '日常 · MVU' }]
const selectedPersona = ref('伊澜')
const messages = ref([{ id: 1, role: 'assistant', text: '雨落了一整晚。伊澜把最后一本书放回高处，回头看见你还站在门边。' }, { id: 2, role: 'user', text: '我不是来借书的，只是想确认这里的灯还亮着。' }, { id: 3, role: 'assistant', text: '“那就进来吧。”她把一盏小灯推到桌边，“今晚的故事，还没有写完。”' }] as { id: number; role: 'assistant' | 'user'; text: string }[])
const draft = ref('')
function send() { const text = draft.value.trim(); if (!text) return; messages.value.push({ id: Date.now(), role: 'user', text }, { id: Date.now() + 1, role: 'assistant', text: '伊澜安静地听完，指尖轻轻敲了一下桌面。“我会记得这句话。”' }); draft.value = '' }
const assetRecords = computed(() => props.surfaceId === 'world' ? [{ icon: '⌘', title: '旧城档案', meta: '24 条目 · 6 个关键词组', value: '启用' }, { icon: '⌘', title: '海港来信', meta: '11 条目 · 2 条契约', value: '草稿' }, { icon: '⌘', title: '王都礼仪', meta: '系统模板 · 只读', value: '模板' }] : props.surfaceId === 'prompt' ? [{ icon: '✧', title: '叙事长篇', meta: '8 个 Prompt 块 · Temperature 0.82', value: '首选' }, { icon: '▤', title: '短篇对话', meta: '4 个 Prompt 块', value: '可用' }, { icon: '◌', title: '系统默认', meta: '内置模板 · 只读', value: '默认' }] : [{ icon: '⌁', title: '清除思维链标记', meta: 'Prompt 阶段 · 排序 #1', value: '启用' }, { icon: '⌁', title: '角色称呼替换', meta: 'Reply 阶段 · 排序 #3', value: '启用' }, { icon: '⌁', title: '清理重复空行', meta: 'Reply 阶段 · 排序 #6', value: '停用' }])
const moodDays = [{ date: '周一', emoji: '☾', label: '平静' }, { date: '周二', emoji: '✦', label: '温暖' }, { date: '周三', emoji: '☁', label: '担忧' }, { date: '今天', emoji: '☾', label: '平静' }]
const insightItems = computed(() => props.surfaceId === 'bond' ? [{ title: '初次信任', meta: '2026/06/29 · 共同完成一次坦白', value: '里程碑' }, { title: '熟悉', meta: '当前阶段 · 128 轮对话', value: '72%' }, { title: '共同记忆', meta: '下一阶段 · 尚差 8%', value: '待解锁' }] : [{ title: '用户偏好雨夜场景', meta: '偏好 · 全局 · 07/15 自动提取', value: '高置信' }, { title: '伊澜害怕失去承诺', meta: '关系 · 角色范围 · 第 84 轮', value: '已确认' }, { title: '坏路灯在旧书店门口', meta: '设定 · 当前对话 · 可编辑', value: '草稿' }])
const devices = [{ icon: '▣', name: 'Windows · Chrome', meta: 'Chicago · 当前会话 · 刚刚', state: '当前' }, { icon: '◐', name: 'iPhone · Safari', meta: '上次活跃：昨天 21:48', state: '在线' }, { icon: '▣', name: 'Windows · Edge', meta: '上次活跃：7 月 10 日', state: '可撤销' }]
</script>

